{
  "name": "SNAP",
  "eligibility": {
    "age": 60,
    "income_limits": "For households with a member 60+ or disabled (Oct 1, 2025 - Sept 30, 2026): No gross income test required. Qualify via Net Income test (limits not explicitly stated in sources, but must be below standard SNAP net limits) and Asset test if gross exceeds 200% FPL. Gross income limits at 200% FPL if applied: 1 person $2608/mo, 2 $3526, 3 $4442, 4 $5358, 5 $6276, 6 $7192, 7 $8108, +$916 each additional. Net income determines benefit amount (e.g., $100 more net income = ~$30 less benefits).[1][2]",
    "asset_limits": "Most households exempt from asset test. Households with member 60+ or disabled: $4500 limit (vs $3000 standard). Counts: cash, bank accounts, non-exempt property. Exempt: primary home, household goods, retirement savings, life insurance cash value (varies), one vehicle (standard exemptions apply).[2][1]",
    "other_requirements": ["West Virginia resident", "U.S. citizen or qualified non-citizen", "Household includes all who buy/prepare food together", "Social Security, pensions, disability count as income", "Medical expenses >$35/mo deductible for 60+/disabled", "Higher shelter deductions allowed", "ABAWD work rules may not apply to 60+ or disabled"][1][2][3]
  },
  "benefits": {
    "type": "financial",
    "value": "Monthly EBT card for food purchases. Amount based on household net income after deductions (e.g., max allotment for 2-person elderly/disabled: ~$546/mo minus 30% net income). Average $140/person/mo in WV (FY2022 data). Minimum/maximum allotments apply; scales with household size and income.[1][4][7]",
    "varies_by": "household_size"
  },
  "application": {
    "methods": ["Online: https://apps.wvpath.wv.gov (via WV PATH portal)", "Phone: Local Income Maintenance office or 1-877-716-1212", "In-person: Local DHHR Income Maintenance office", "Mail: Form to local office (download from bfa.wv.gov)"],
    "processing_time": "Typically 30 days; expedited if very low income (7 days). No specific WV elderly timeline stated.",
    "waitlist": null,
    "forms": ["SNAP Application (via WV PATH or Form SNAP-1 downloadable from bfa.wv.gov/snap)"],
    "documents": ["Proof of ID", "Income (pay stubs, Social Security award letters, pensions)", "Expenses (rent/mortgage receipts, utility bills, medical costs >$35/mo for 60+/disabled)", "Assets if applicable (bank statements)", "Household size proof", "Disability verification if claimed"][2]
  },
  "geography": {
    "statewide": true,
    "restrictions": null,
    "regional_variations": "Administered uniformly statewide by Bureau for Family Assistance via local Income Maintenance offices; no major differences noted in eligibility/benefits, but processing/wait times may vary by local office workload.",
    "offices_or_providers": ["Local DHHR Income Maintenance offices by county (find via bfa.wv.gov/snap)"]
  },
  "official_source": "https://bfa.wv.gov/snap",
  "gotchas": ["Elderly/disabled skip gross income test but must meet net income/asset if gross >200% FPL", "Only ~34% eligible seniors receive benefits (underutilization)", "Medical expenses over $35/mo and excess shelter costs deductible—key for qualification", "Include all household who share food prep", "Assets $4500 limit applies only if gross income test failed", "Social Security/pensions count as income", "No gross test makes WV broader than federal standard"][1][2][3][7],
  "data_shape_notes": "Elderly/disabled households exempt from gross income test (net + asset only if needed); expanded deductions for medical/shelter; benefits scale by household size and net income; statewide with local offices"
}

{
