    "value": "Free, one-on-one personalized health insurance counseling; information and printed materials; referrals to agencies; assistance with Medicare Part A/B, Part D, Medigap, Medicare Advantage (HMOs/PPOs), long-term care insurance, Medicare Savings Programs (QMB/SLMB/QI), prescription drug assistance, Medicaid, and other insurance/free health care programs. Counselors help understand benefits, compare options, and avoid overpaying.[4][8]",
    "varies_by": "not_applicable"
  },
  "application": {
    "methods": ["Phone: 1-877-987-4463[7]", "In-person: County senior centers throughout WV or main office at West Virginia Bureau of Senior Services, 1900 Kanawha Boulevard East, 3rd Floor Town Center Mall, Charleston WV 25305-0160[6][8]", "Website: West Virginia Website (via shiphelp.org link, for contact and appointments)[7]"],
    "processing_time": "No formal processing; services provided via appointment scheduling upon contact. No specified timeline.[4]",
    "waitlist": null,
    "forms": ["No specific forms required; contact to make an appointment[4]"],
    "documents": ["No documents typically needed upfront; may request Medicare card or insurance details during counseling session (not specified for application)[4]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "None; available statewide to WV residents[6][7][8]",
    "regional_variations": "Delivered through main office in Charleston and many county senior centers; potential differences in local counselor availability or appointment scheduling by county, but core services uniform[8]",
    "offices_or_providers": ["Main office: West Virginia Bureau of Senior Services, 1900 Kanawha Boulevard East, 3rd Floor Town Center Mall, Charleston WV 25305-0160[6]", "County senior centers throughout WV[8]"]
  },
  "official_source": "https://www.shiphelp.org/ships/west-virginia/ (links to WV SHIP site); Bureau of Senior Services contact via CMS[6][7]",
  "gotchas": ["Not a financial aid or healthcare provision program—only free counseling and information, no direct payments or coverage[4]", "People confuse with CHIP (children's program) or Medicaid due to similar acronyms; SHIP is Medicare-specific[1][4][8]", "Must be Medicare beneficiary; does not cover non-Medicare individuals[4][8]", "Services are appointment-based; call ahead as no walk-in guarantee at county centers[8]"],
  "data_shape_notes": "no income test; counseling-only service, not benefits-paying; delivered via statewide network of senior centers with central phone line"
}

