{
  "name": "Lighthouse Program",
  "eligibility": {
    "age": 60,
    "income_limits": "No strict income limits or asset disqualification; eligibility is financial based on a sliding fee scale according to the individual's (and spouse's, if applicable) annual income. Designed as a program of last resort for those whose income/assets disqualify them from Medicaid but cannot afford private pay without hardship. Exact dollar thresholds not specified in sources; determined locally.[1][2][3][4][5]",
    "asset_limits": "No asset test mentioned; program targets those disqualified from Medicaid by income/assets but facing financial hardship for private care. Assets do not disqualify.[2][4][5]",
    "other_requirements": [
      "West Virginia resident.[3][4]",
      "Medically eligible based on functional evaluation/assessment by the local senior aging program's registered nurse (RN), assessing needs in areas like personal care, mobility, nutrition, and environment.[1][2][3][4][5]"
    ]
  },
  "benefits": {
    "type": "service",
    "value": "In-home supportive services up to 60 hours per month, based on need and caregiver availability. Services include: personal care (bathing, dressing, grooming, eating, toileting); mobility (transferring in/out of bed, walking); nutrition (meal preparation, eating, grocery/pharmacy shopping); environment (light housecleaning, making/changing bed, laundry). Provided by caregivers employed by local senior aging programs.[1][2][3][4][5]",
    "varies_by": "priority_tier"
  },
  "application": {
    "methods": [
      "Contact your local county senior program (specific contacts vary by county, e.g., Preston County: (304) 329-6272).[2]",
      "Call West Virginia Bureau for Senior Services toll-free: 1-877-987-3646.[1][3]"
    ],
    "processing_time": "Not specified in sources.",
    "waitlist": "Services limited by need and availability of caregivers; potential wait implied but no formal waitlist details.[3]",
    "forms": [],
    "documents": [
      "Income documentation for sliding fee determination (individual and spouse if applicable).[2][5]",
      "Prepare for RN functional evaluation (no specific documents listed; assessment determines medical eligibility).[1][2][3][4][5]"
    ]
  },
  "geography": {
    "statewide": true,
    "restrictions": "Available in each county of West Virginia.",
    "regional_variations": "Administered by over 140 local senior aging organizations/providers (e.g., Preston County Senior Citizens, Inc.; Nicholas Community Action Partnership; CCCSO). Services, contacts, and processing may vary by county/provider, but core eligibility and benefits consistent statewide.[1][2][3][4][5]",
    "offices_or_providers": ["Local county senior programs; WV Bureau for Senior Services (state oversight). Examples: Preston County (304) 329-6272; Nicholas CAP; contact via 1-877-987-3646 for county-specific."]
  },
  "official_source": "https://www.wvseniorservices.gov",
  "gotchas": [
    "Not free—uses sliding fee scale based on income; not income-disregarded.[1][2][3][5]",
    "Program of last resort for non-Medicaid eligible; won't substitute for Medicaid or private pay.[4][5]",
    "Hours capped at 60/month, based on need/availability—may not meet full needs.[2][3]",
    "Must contact local county program (not centralized); statewide hotline routes to locals.[1][2][3]",
    "Medical eligibility requires RN assessment; functional needs in ADLs (activities of daily living) essential.[1][2][3][4][5]"
  ],
  "data_shape_notes": "State-funded, county-administered via local aging agencies; sliding fee (not asset-tested); up to 60 hours/month capped by need/availability; targets Medicaid-ineligible seniors with functional needs."
}

